// src/components/Common/ownerCard.js
import React, { useState, useEffect } from "react";

export default function OwnerCard({ ownerId, restaurantId, onViewProfile }) {
  const [owner, setOwner] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showDetails, setShowDetails] = useState(false);

  // بيانات تجريبية للمالكين (ستأتي من API أو localStorage لاحقاً)
  const ownersData = {
    1: {
      id: 1,
      name: "Ahmed Benali",
      role: "Propriétaire & Gérant",
      restaurant: "Restaurant Andalous",
      restaurantId: 1,
      email: "ahmed.benali@andalus.dz",
      phone: "+213 5 55 55 55 55",
      location: "Alger, Algérie",
      experience: "15 ans d'expérience",
      bio: "Passionné par la cuisine traditionnelle algérienne, j'ai fondé le Restaurant Andalous pour faire découvrir les saveurs authentiques de notre terroir.",
      image: "https://randomuser.me/api/portraits/men/32.jpg",
      coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      joinDate: "2010",
      employees: 12,
      rating: 4.8,
      socialLinks: {
        facebook: "https://facebook.com/ahmed.benali",
        instagram: "https://instagram.com/ahmed.benali",
        linkedin: "https://linkedin.com/in/ahmed-benali"
      },
      achievements: [
        "🏆 Meilleur restaurant traditionnel 2022",
        "⭐ Certification qualité 5 étoiles",
        "👨‍🍳 Chef formateur certifié"
      ]
    },
    2: {
      id: 2,
      name: "Jean Dupont",
      role: "Fondateur & Chef",
      restaurant: "Café Parisien",
      restaurantId: 2,
      email: "jean.dupont@cafeparisien.fr",
      phone: "+33 6 12 34 56 78",
      location: "Paris, France",
      experience: "20 ans d'expérience",
      bio: "Passionné par l'art du café et la pâtisserie française, j'ai ouvert le Café Parisien pour offrir une expérience authentique aux amateurs de bonne cuisine.",
      image: "https://randomuser.me/api/portraits/men/45.jpg",
      coverImage: "https://images.unsplash.com/photo-1501339847302-ac426a4a7cbb",
      joinDate: "2005",
      employees: 8,
      rating: 4.5,
      socialLinks: {
        facebook: "https://facebook.com/jean.dupont",
        instagram: "https://instagram.com/jean.dupont",
        twitter: "https://twitter.com/jean.dupont"
      },
      achievements: [
        "🏆 Meilleur café de Paris 2020",
        "⭐ Élu pâtissier de l'année 2021"
      ]
    },
    3: {
      id: 3,
      name: "Marco Rossi",
      role: "Chef Italien & Propriétaire",
      restaurant: "La Piazza Italia",
      restaurantId: 3,
      email: "marco.rossi@lapiazza.it",
      phone: "+39 6 12 34 56 78",
      location: "Rome, Italie",
      experience: "25 ans d'expérience",
      bio: "Je perpétue la tradition culinaire italienne familiale depuis trois générations. Chaque plat raconte une histoire d'amour pour la cuisine italienne.",
      image: "https://randomuser.me/api/portraits/men/68.jpg",
      coverImage: "https://images.unsplash.com/photo-1555396273-367ea4eb4db5",
      joinDate: "1998",
      employees: 15,
      rating: 4.7,
      socialLinks: {
        facebook: "https://facebook.com/marco.rossi",
        instagram: "https://instagram.com/marco.rossi",
        linkedin: "https://linkedin.com/in/marco-rossi"
      },
      achievements: [
        "🏆 Étoile Michelin 2019",
        "⭐ Meilleur restaurant italien de Rome",
        "👨‍🍳 Maître cuisinier d'Italie"
      ]
    },
    4: {
      id: 4,
      name: "Kenji Tanaka",
      role: "Maître Sushi & Propriétaire",
      restaurant: "Sushi Master",
      restaurantId: 4,
      email: "kenji.tanaka@sushimaster.jp",
      phone: "+81 3 12 34 56 78",
      location: "Tokyo, Japon",
      experience: "30 ans d'expérience",
      bio: "Formé au Japon dans la plus pure tradition des maîtres sushi, je vous invite à découvrir l'art du sushi authentique dans mon établissement.",
      image: "https://randomuser.me/api/portraits/men/89.jpg",
      coverImage: "https://images.unsplash.com/photo-1579871494447-9811cf80d66c",
      joinDate: "1995",
      employees: 20,
      rating: 4.9,
      socialLinks: {
        facebook: "https://facebook.com/kenji.tanaka",
        instagram: "https://instagram.com/kenji.tanaka",
        twitter: "https://twitter.com/kenji.tanaka"
      },
      achievements: [
        "🏆 Meilleur sushi chef du Japon 2018",
        "⭐ 3 étoiles au guide gastronomique",
        "👨‍🍳 Ambassadeur de la cuisine japonaise"
      ]
    }
  };

  useEffect(() => {
    // محاكاة تحميل البيانات من API
    setLoading(true);
    setTimeout(() => {
      if (ownerId && ownersData[ownerId]) {
        setOwner(ownersData[ownerId]);
      } else if (restaurantId) {
        // البحث عن المالك حسب ID المطعم
        const foundOwner = Object.values(ownersData).find(o => o.restaurantId === restaurantId);
        setOwner(foundOwner || null);
      }
      setLoading(false);
    }, 500);
  }, [ownerId, restaurantId]);

  if (loading) {
    return (
      <div className="owner-card-loading">
        <div className="loading-spinner"></div>
        <p>Chargement du profil propriétaire...</p>
      </div>
    );
  }

  if (!owner) {
    return (
      <div className="owner-card-error">
        <div className="error-icon">👤</div>
        <p>Propriétaire non trouvé</p>
      </div>
    );
  }

  const styles = `
    .owner-card {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      border: 2px solid rgba(34, 197, 94, 0.3);
      overflow: hidden;
      transition: all 0.3s ease;
      cursor: pointer;
      box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
    }
    
    .owner-card:hover {
      transform: translateY(-5px);
      border-color: #22c55e;
      box-shadow: 0 15px 40px rgba(34, 197, 94, 0.2);
    }
    
    .owner-cover {
      height: 120px;
      background-size: cover;
      background-position: center;
      position: relative;
    }
    
    .owner-avatar-wrapper {
      position: relative;
      text-align: center;
      margin-top: -50px;
      margin-bottom: 15px;
    }
    
    .owner-avatar {
      width: 100px;
      height: 100px;
      border-radius: 50%;
      border: 4px solid #22c55e;
      background: #1a1a3a;
      object-fit: cover;
      box-shadow: 0 5px 20px rgba(0, 0, 0, 0.3);
    }
    
    .owner-name {
      font-size: 1.4rem;
      font-weight: bold;
      color: white;
      text-align: center;
      margin: 10px 0 5px;
    }
    
    .owner-role {
      font-size: 0.85rem;
      color: #22c55e;
      text-align: center;
      margin-bottom: 15px;
    }
    
    .owner-restaurant {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      margin-bottom: 15px;
      font-size: 0.9rem;
      color: rgba(255,255,255,0.7);
    }
    
    .owner-stats {
      display: flex;
      justify-content: space-around;
      padding: 15px;
      border-top: 1px solid rgba(255,255,255,0.1);
      border-bottom: 1px solid rgba(255,255,255,0.1);
      margin: 10px 0;
    }
    
    .owner-stat {
      text-align: center;
    }
    
    .owner-stat-value {
      font-size: 1.3rem;
      font-weight: bold;
      color: #22c55e;
    }
    
    .owner-stat-label {
      font-size: 0.7rem;
      color: rgba(255,255,255,0.5);
    }
    
    .owner-bio {
      font-size: 0.85rem;
      color: rgba(255,255,255,0.7);
      line-height: 1.5;
      padding: 0 15px;
      margin-bottom: 15px;
      text-align: center;
    }
    
    .owner-contact {
      display: flex;
      justify-content: center;
      gap: 15px;
      margin-bottom: 15px;
    }
    
    .contact-icon {
      width: 35px;
      height: 35px;
      border-radius: 50%;
      background: rgba(34, 197, 94, 0.2);
      display: flex;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: all 0.3s;
      color: #22c55e;
      font-size: 1.1rem;
    }
    
    .contact-icon:hover {
      background: #22c55e;
      color: white;
      transform: scale(1.1);
    }
    
    .owner-achievements {
      padding: 10px 15px;
      background: rgba(34, 197, 94, 0.1);
      border-radius: 15px;
      margin: 0 15px 15px;
    }
    
    .achievement-title {
      font-size: 0.75rem;
      color: rgba(255,255,255,0.6);
      margin-bottom: 8px;
    }
    
    .achievement-item {
      font-size: 0.75rem;
      color: #22c55e;
      padding: 3px 0;
    }
    
    .view-profile-btn {
      width: calc(100% - 30px);
      margin: 0 15px 20px;
      padding: 12px;
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .view-profile-btn:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 20px rgba(34, 197, 94, 0.4);
    }
    
    /* Modal styles */
    .owner-modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.95);
      backdrop-filter: blur(12px);
      z-index: 10000;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    .owner-modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 0;
      max-width: 600px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      animation: slideUp 0.4s ease;
    }
    
    .owner-modal-cover {
      height: 180px;
      background-size: cover;
      background-position: center;
      position: relative;
    }
    
    .owner-modal-avatar {
      position: absolute;
      bottom: -50px;
      left: 30px;
      width: 100px;
      height: 100px;
      border-radius: 50%;
      border: 4px solid #22c55e;
      background: #1a1a3a;
      object-fit: cover;
    }
    
    .owner-modal-body {
      padding: 60px 25px 25px;
    }
    
    .owner-modal-name {
      font-size: 1.8rem;
      font-weight: bold;
      color: white;
      margin-bottom: 5px;
    }
    
    .owner-modal-role {
      font-size: 1rem;
      color: #22c55e;
      margin-bottom: 15px;
    }
    
    .owner-modal-info {
      margin: 20px 0;
    }
    
    .info-row {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 12px;
      color: rgba(255,255,255,0.7);
      font-size: 0.9rem;
    }
    
    .info-icon {
      width: 30px;
      color: #22c55e;
    }
    
    .close-modal-btn {
      position: absolute;
      top: 15px;
      right: 20px;
      background: none;
      border: none;
      color: white;
      font-size: 28px;
      cursor: pointer;
      z-index: 10;
    }
    
    .close-modal-btn:hover {
      color: #ef4444;
    }
    
    .owner-social-links {
      display: flex;
      gap: 15px;
      margin-top: 20px;
      padding-top: 20px;
      border-top: 1px solid rgba(255,255,255,0.1);
    }
    
    .social-link {
      width: 40px;
      height: 40px;
      border-radius: 50%;
      background: rgba(34, 197, 94, 0.2);
      display: flex;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: all 0.3s;
      color: #22c55e;
      font-size: 1.2rem;
      text-decoration: none;
    }
    
    .social-link:hover {
      background: #22c55e;
      color: white;
      transform: scale(1.1);
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    @keyframes slideUp {
      from { opacity: 0; transform: translateY(30px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    .loading-spinner {
      width: 40px;
      height: 40px;
      border: 3px solid rgba(34,197,94,0.2);
      border-top-color: #22c55e;
      border-radius: 50%;
      animation: spin 0.8s linear infinite;
      margin: 20px auto;
    }
    
    @keyframes spin {
      to { transform: rotate(360deg); }
    }
    
    .owner-card-loading, .owner-card-error {
      background: rgba(255,255,255,0.05);
      border-radius: 20px;
      padding: 30px;
      text-align: center;
      color: rgba(255,255,255,0.6);
    }
    
    .error-icon {
      font-size: 3rem;
      margin-bottom: 10px;
      opacity: 0.5;
    }
  `;

  const handleViewProfile = () => {
    if (onViewProfile) {
      onViewProfile(owner);
    } else {
      setShowDetails(true);
    }
  };

  return (
    <>
      <style>{styles}</style>
      
      <div className="owner-card" onClick={handleViewProfile}>
        <div className="owner-cover" style={{ backgroundImage: `url(${owner.coverImage})` }}></div>
        
        <div className="owner-avatar-wrapper">
          <img src={owner.image} alt={owner.name} className="owner-avatar" />
        </div>
        
        <h3 className="owner-name">{owner.name}</h3>
        <p className="owner-role">{owner.role}</p>
        
        <div className="owner-restaurant">
          <span>🏪</span>
          <span>{owner.restaurant}</span>
        </div>
        
        <div className="owner-stats">
          <div className="owner-stat">
            <div className="owner-stat-value">{owner.experience.split(' ')[0]}+</div>
            <div className="owner-stat-label">années</div>
          </div>
          <div className="owner-stat">
            <div className="owner-stat-value">{owner.rating}</div>
            <div className="owner-stat-label">⭐ note</div>
          </div>
          <div className="owner-stat">
            <div className="owner-stat-value">{owner.employees}</div>
            <div className="owner-stat-label">employés</div>
          </div>
        </div>
        
        <p className="owner-bio">{owner.bio.substring(0, 100)}...</p>
        
        <div className="owner-contact">
          <div className="contact-icon" onClick={(e) => { e.stopPropagation(); window.location.href = `mailto:${owner.email}`; }}>📧</div>
          <div className="contact-icon" onClick={(e) => { e.stopPropagation(); window.location.href = `tel:${owner.phone}`; }}>📞</div>
          <div className="contact-icon" onClick={(e) => { e.stopPropagation(); if(owner.socialLinks.instagram) window.open(owner.socialLinks.instagram, '_blank'); }}>📷</div>
        </div>
        
        <button className="view-profile-btn" onClick={(e) => { e.stopPropagation(); handleViewProfile(); }}>
          👤 Voir le profil complet
        </button>
      </div>
      
      {/* Modal avec détails complets */}
      {showDetails && (
        <div className="owner-modal-overlay" onClick={() => setShowDetails(false)}>
          <div className="owner-modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-modal-btn" onClick={() => setShowDetails(false)}>✕</button>
            
            <div className="owner-modal-cover" style={{ backgroundImage: `url(${owner.coverImage})` }}>
              <img src={owner.image} alt={owner.name} className="owner-modal-avatar" />
            </div>
            
            <div className="owner-modal-body">
              <h2 className="owner-modal-name">{owner.name}</h2>
              <p className="owner-modal-role">{owner.role}</p>
              
              <div className="owner-modal-info">
                <div className="info-row">
                  <span className="info-icon">🏪</span>
                  <span><strong>{owner.restaurant}</strong> - Propriétaire</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">📍</span>
                  <span>{owner.location}</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">📅</span>
                  <span>Membre depuis {owner.joinDate}</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">⭐</span>
                  <span>Note moyenne: {owner.rating}/5</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">👥</span>
                  <span>{owner.employees} employés</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">📧</span>
                  <span>{owner.email}</span>
                </div>
                <div className="info-row">
                  <span className="info-icon">📞</span>
                  <span>{owner.phone}</span>
                </div>
              </div>
              
              <div className="owner-achievements" style={{ margin: '15px 0' }}>
                <div className="achievement-title">🏆 Réalisations</div>
                {owner.achievements.map((achievement, idx) => (
                  <div key={idx} className="achievement-item">{achievement}</div>
                ))}
              </div>
              
              <p style={{ color: 'rgba(255,255,255,0.8)', lineHeight: '1.6', marginTop: '15px' }}>
                {owner.bio}
              </p>
              
              <div className="owner-social-links">
                {owner.socialLinks.facebook && (
                  <a href={owner.socialLinks.facebook} target="_blank" rel="noopener noreferrer" className="social-link">
                    <i className="fab fa-facebook-f"></i>
                  </a>
                )}
                {owner.socialLinks.instagram && (
                  <a href={owner.socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="social-link">
                    <i className="fab fa-instagram"></i>
                  </a>
                )}
                {owner.socialLinks.twitter && (
                  <a href={owner.socialLinks.twitter} target="_blank" rel="noopener noreferrer" className="social-link">
                    <i className="fab fa-twitter"></i>
                  </a>
                )}
                {owner.socialLinks.linkedin && (
                  <a href={owner.socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="social-link">
                    <i className="fab fa-linkedin-in"></i>
                  </a>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
